// Sélecteur de thème rotatif
const now = new Date();
const dayOfWeek = now.getDay(); // 1=Lundi, 3=Mercredi, 5=Vendredi

const startOfYear = new Date(now.getFullYear(), 0, 1);
const weekNumber = Math.ceil(((now - startOfYear) / 86400000 + startOfYear.getDay() + 1) / 7);
const cycleWeek = ((weekNumber - 1) % 4) + 1;

const themes = {
  1: { name: "Commercial",
    1: { type: "module_presentation", sujet: "Module Clients + Leads", angle: "Gérez vos prospects en un clic", format: "carousel" },
    3: { type: "astuce", sujet: "Astuce CRM", angle: "3 erreurs qui vous font perdre des clients", format: "image" },
    5: { type: "temoignage", sujet: "Témoignage artisan", angle: "Comment doubler ses leads en 30 jours", format: "video" }
  },
  2: { name: "Facturation",
    1: { type: "module_presentation", sujet: "Module Facturation + Devis", angle: "Facturez en 30 secondes", format: "carousel" },
    3: { type: "astuce", sujet: "Astuce compta", angle: "TVA auto, écritures auto : zéro saisie", format: "image" },
    5: { type: "temoignage", sujet: "ROI client", angle: "2h/semaine gagnées grâce à l'automatisation", format: "video" }
  },
  3: { name: "IA & Automation",
    1: { type: "module_presentation", sujet: "Agent Téléphonique IA", angle: "Votre secrétaire IA qui répond 24h/24", format: "carousel" },
    3: { type: "astuce", sujet: "Astuce automation", angle: "5 tâches à automatiser dès aujourd'hui", format: "image" },
    5: { type: "temoignage", sujet: "Démo live", angle: "Appel en direct à l'agent IA", format: "video" }
  },
  4: { name: "Métiers spécifiques",
    1: { type: "module_presentation", sujet: "Modules BTP + Projets", angle: "Gérez vos chantiers de A à Z", format: "carousel" },
    3: { type: "astuce", sujet: "Astuce RH/Équipe", angle: "Pointages, congés, paie : tout automatisé", format: "image" },
    5: { type: "temoignage", sujet: "Partenariat", angle: "Devenez partenaire — 10% de commission", format: "video" }
  }
};

const weekTheme = themes[cycleWeek];
const dayContent = weekTheme[dayOfWeek] || weekTheme[1];

return [{
  json: {
    cycle_week: cycleWeek,
    week_theme: weekTheme.name,
    day_of_week: dayOfWeek,
    content_type: dayContent.type,
    sujet: dayContent.sujet,
    angle: dayContent.angle,
    format_visuel: dayContent.format,
    date_publication: now.toISOString(),
    brand_name: "TalosPrimes",
    brand_description: "Plateforme SaaS de gestion tout-en-un pour TPE/PME, artisans et BTP. Modules: Facturation, Devis, CRM Clients, Leads, Agent IA téléphonique (Léa), Comptabilité, Gestion Équipe, Projets, BTP, Tickets, Marketing Digital.",
    brand_url: "https://talosprimes.com",
    target_audience: "TPE/PME, artisans, entreprises BTP en France"
  }
}];

