// Parser la réponse OpenAI API
const input = $input.first().json;
let content;

try {
  // L'API OpenAI retourne: { choices: [{ message: { content: '...' } }] }
  const rawText = input.choices?.[0]?.message?.content || input.message?.content || input.text || input.content || JSON.stringify(input);

  // Nettoyer le texte (enlever backticks markdown si présents)
  let cleanText = rawText.trim();
  if (cleanText.startsWith('```json')) cleanText = cleanText.slice(7);
  if (cleanText.startsWith('```')) cleanText = cleanText.slice(3);
  if (cleanText.endsWith('```')) cleanText = cleanText.slice(0, -3);
  cleanText = cleanText.trim();

  content = JSON.parse(cleanText);
} catch (e) {
  return [{
    json: {
      error: true,
      message: "Erreur parsing réponse IA: " + e.message,
      raw: JSON.stringify(input).substring(0, 500)
    }
  }];
}

const theme = ((() => { try { return $('Sélecteur Thème').first()?.json; } catch(e) {} try { return $('Parser Webhook').first()?.json; } catch(e) {} return {}; })());

return [{
  json: {
    success: true,
    theme: theme,
    tiktok: content.tiktok || {},
    instagram: content.instagram || {},
    facebook: content.facebook || {},
    visual_prompt: content.visual_prompt || "",
    generated_at: new Date().toISOString()
  }
}];

// ========================================
// CONFIGURATION META / FACEBOOK / INSTAGRAM
// ========================================
// Remplacez ces valeurs par vos vrais tokens.
// Cela remplace les $env qui ne fonctionnent pas.
// ========================================

const META_CONFIG = {
  PAGE_ACCESS_TOKEN: 'A_REMPLACER_PAR_LONG_LIVED_TOKEN',
  PAGE_ID: '1029257496936725',
  INSTAGRAM_USER_ID: '1002158382768057',
  DEFAULT_IMAGE_URL: 'https://talosprimes.com/og-image.png'
};

const data = $input.first().json;
if (data.error) return [$input.first()];

const fb = data.facebook || {};
const hashtags = (fb.hashtags || []).map(h => h.startsWith('#') ? h : '#' + h).join(' ');
const fullText = (fb.text || data.theme?.angle || '') + '\n\n' + hashtags;

return [{
  json: {
    platform: "facebook",
    message: fullText,
    link: "https://talosprimes.com",
    meta_page_id: META_CONFIG.PAGE_ID,
    meta_access_token: META_CONFIG.PAGE_ACCESS_TOKEN,
    instagram_user_id: META_CONFIG.INSTAGRAM_USER_ID,
    default_image_url: META_CONFIG.DEFAULT_IMAGE_URL
  }
}];

// Formater le résultat Facebook
const resp = $input.first().json;
const statusCode = resp.statusCode || 200;
const body = resp.body || resp;

return [{
  json: {
    platform: "facebook",
    success: statusCode >= 200 && statusCode < 300,
    post_id: body.id || body.body?.id || null,
    error: statusCode >= 400 ? (body.error?.message || JSON.stringify(body).substring(0, 200)) : null
  }
}];

// Préparer la publication Instagram via Meta Graph API
// Récupère les config Meta depuis le noeud Préparer Facebook (même source)
const data = $input.first().json;
if (data.error) return [{ json: { platform: 'instagram', success: false, post_id: null, error: data.message } }];

// ========================================
// CONFIGURATION META (même que Facebook)
// ========================================
const META_CONFIG = {
  PAGE_ACCESS_TOKEN: 'A_REMPLACER_PAR_LONG_LIVED_TOKEN',
  INSTAGRAM_USER_ID: '1002158382768057',
  DEFAULT_IMAGE_URL: 'https://talosprimes.com/og-image.png'
};

const ig = data.instagram || {};
const hashtags = (ig.hashtags || []).map(h => h.startsWith('#') ? h : '#' + h).join(' ');
const caption = (ig.caption || data.theme?.angle || '') + '\n\n' + hashtags;

return [{
  json: {
    platform: "instagram",
    caption: caption,
    instagram_user_id: META_CONFIG.INSTAGRAM_USER_ID,
    meta_access_token: META_CONFIG.PAGE_ACCESS_TOKEN,
    default_image_url: META_CONFIG.DEFAULT_IMAGE_URL
  }
}];

// Formater le résultat Instagram
const resp = $input.first().json;
const statusCode = resp.statusCode || 200;
const body = resp.body || resp;

return [{
  json: {
    platform: "instagram",
    success: statusCode >= 200 && statusCode < 300 && !body.error,
    post_id: body.id || body.body?.id || null,
    error: body.error?.message || (statusCode >= 400 ? JSON.stringify(body).substring(0, 200) : null)
  }
}];

// Préparer TikTok (placeholder — nécessite app review)
const data = $input.first().json;
if (data.error) return [{ json: { platform: 'tiktok', success: false, post_id: null, error: data.message } }];

const tt = data.tiktok || {};
const hashtags = (tt.hashtags || []).map(h => h.startsWith('#') ? h : '#' + h).join(' ');
const caption = (tt.caption || data.theme?.angle || '') + ' ' + hashtags;

// TikTok app est encore en Draft — on skip la publication réelle
// et on log juste le contenu généré
return [{
  json: {
    platform: "tiktok",
    success: false,
    post_id: null,
    error: "TikTok app en cours de review — publication différée",
    caption_generated: caption.substring(0, 150)
  }
}];

// Collecter les résultats des 3 plateformes (Instagram peut être omis s'il est désactivé)
const items = $input.all();

const theme = ((() => { try { return $('Sélecteur Thème').first()?.json; } catch(e) {} try { return $('Parser Webhook').first()?.json; } catch(e) {} return {}; })());

// Récupérer infos du chemin manuel si disponible
const manuelInfo = ((() => { try { return $('Publier Manuel Direct').first()?.json; } catch(e) { return null; } })());

const summary = {
  date: new Date().toISOString(),
  theme: manuelInfo?.week_theme || theme.week_theme || 'N/A',
  sujet: manuelInfo?.sujet || theme.sujet || 'N/A',
  angle: theme.angle || manuelInfo?.message?.substring(0, 50) || 'N/A',
  type: manuelInfo?.content_type || theme.content_type || 'N/A',
  tenant_id: '00000000-0000-0000-0000-000000000001',
  platforms: {}
};

for (const item of items) {
  const r = item.json;
  if (r.platform) {
    summary.platforms[r.platform] = {
      success: !!r.success,
      post_id: r.post_id || null,
      error: r.error || null
    };
  }
}

// Ne PAS ajouter de fausses entrées pour les plateformes désactivées
// On ne log que les plateformes réellement utilisées

return [{ json: summary }];

// Préparer les données pour insertion SQL avec échappement des quotes
const data = $input.first().json;

function esc(val) {
  if (val === null || val === undefined) return 'NULL';
  return "'" + String(val).replace(/'/g, "''") + "'";
}

// Ne logger que les plateformes réellement présentes dans les résultats
const platforms = Object.keys(data.platforms || {});
if (platforms.length === 0) platforms.push('facebook');
const rows = platforms.map(p => {
  const result = data.platforms?.[p] || {};
  const status = result.success ? 'publie' : 'erreur';
  const postId = result.post_id ? esc(result.post_id) : 'NULL';
  return `(gen_random_uuid(), ${esc(data.tenant_id)}::uuid, ${esc(p)}, ${esc(data.type)}, ${esc(data.sujet)}, ${esc(data.angle)}, NOW(), ${esc(status)}, ${postId}, NOW(), NOW())`;
});

const query = `INSERT INTO marketing_posts (id, tenant_id, plateforme, type, sujet, contenu_texte, date_publication, status, post_external_id, created_at, updated_at)
VALUES
  ${rows.join(',\n  ')}
ON CONFLICT DO NOTHING;`;

return [{ json: { query } }];

// Formater la notification Telegram
const data = ((() => { try { return $('Merger Résultats').first().json; } catch(e) { return $input.first().json; } })());

const platformEmojis = { facebook: '📘', instagram: '📸', tiktok: '🎵' };

let message = `🚀 *Publication Marketing*\n`;
message += `📅 ${data.date?.split('T')[0] || 'N/A'}\n`;
message += `📝 Thème: ${data.theme || 'N/A'}\n`;
message += `💡 Sujet: ${data.sujet || 'N/A'}\n\n`;

const platforms = data.platforms || {};
for (const [platform, result] of Object.entries(platforms)) {
  const emoji = platformEmojis[platform] || '📱';
  const status = result.success ? '✅' : '❌';
  message += `${emoji} ${platform}: ${status}`;
  if (result.post_id) message += ` (ID: ${result.post_id})`;
  if (result.error) message += ` — ${result.error}`;
  message += '\n';
}

message += `\n_TalosPrimes — Votre gestion, automatisée._`;

return [{
  json: {
    chatId: "6296082748",
    message: message
  }
}];

// Gestion d'erreur — notification Telegram
const error = $input.first().json;

const message = `❌ *ERREUR Marketing Workflow*\n\n`
  + `📅 ${new Date().toISOString().split('T')[0]}\n`
  + `⚠️ ${error.message || JSON.stringify(error).substring(0, 500)}\n\n`
  + `Vérifiez les credentials et les API dans n8n.`;

return [{
  json: {
    chatId: "6296082748",
    message: message
  }
}];

// Parser les paramètres du webhook
const body = $input.first().json.body || $input.first().json;

const now = new Date();
const dayOfWeek = now.getDay();
const startOfYear = new Date(now.getFullYear(), 0, 1);
const weekNumber = Math.ceil(((now - startOfYear) / 86400000 + startOfYear.getDay() + 1) / 7);
const cycleWeek = ((weekNumber - 1) % 4) + 1;

const themes = {
  1: { name: "Commercial",
    1: { type: "module_presentation", sujet: "Module Clients + Leads", angle: "Gérez vos prospects en un clic", format: "carousel" },
    3: { type: "astuce", sujet: "Astuce CRM", angle: "3 erreurs qui vous font perdre des clients", format: "image" },
    5: { type: "temoignage", sujet: "Témoignage artisan", angle: "Comment doubler ses leads en 30 jours", format: "video" }
  },
  2: { name: "Facturation",
    1: { type: "module_presentation", sujet: "Module Facturation + Devis", angle: "Facturez en 30 secondes", format: "carousel" },
    3: { type: "astuce", sujet: "Astuce compta", angle: "TVA auto, écritures auto : zéro saisie", format: "image" },
    5: { type: "temoignage", sujet: "ROI client", angle: "2h/semaine gagnées grâce à l'automatisation", format: "video" }
  },
  3: { name: "IA & Automation",
    1: { type: "module_presentation", sujet: "Agent Téléphonique IA", angle: "Votre secrétaire IA qui répond 24h/24", format: "carousel" },
    3: { type: "astuce", sujet: "Astuce automation", angle: "5 tâches à automatiser dès aujourd'hui", format: "image" },
    5: { type: "temoignage", sujet: "Démo live", angle: "Appel en direct à l'agent IA", format: "video" }
  },
  4: { name: "Métiers spécifiques",
    1: { type: "module_presentation", sujet: "Modules BTP + Projets", angle: "Gérez vos chantiers de A à Z", format: "carousel" },
    3: { type: "astuce", sujet: "Astuce RH/Équipe", angle: "Pointages, congés, paie : tout automatisé", format: "image" },
    5: { type: "temoignage", sujet: "Partenariat", angle: "Devenez partenaire — 10% de commission", format: "video" }
  }
};

const forcedWeek = body.cycle_week || cycleWeek;
const forcedDay = body.day_of_week || dayOfWeek || 1;
const weekTheme = themes[forcedWeek] || themes[1];
const dayContent = weekTheme[forcedDay] || weekTheme[1];

// Contenu utilisateur (si fourni depuis l'UI)
const userContent = body.contenu_texte || '';
const userHashtags = body.hashtags || '';
const userPlateforme = body.plateforme || '';

return [{
  json: {
    cycle_week: forcedWeek,
    week_theme: body.week_theme || weekTheme.name,
    day_of_week: forcedDay,
    content_type: body.type || body.content_type || dayContent.type,
    sujet: body.sujet || dayContent.sujet,
    angle: body.angle || dayContent.angle,
    format_visuel: body.format_visuel || dayContent.format,
    date_publication: now.toISOString(),
    brand_name: "TalosPrimes",
    brand_description: "Plateforme SaaS de gestion tout-en-un pour TPE/PME, artisans et BTP.",
    brand_url: "https://talosprimes.com",
    target_audience: "TPE/PME, artisans, entreprises BTP en France",
    source: "webhook_manual",
    has_user_content: !!userContent,
    user_content: userContent,
    user_hashtags: userHashtags,
    user_plateforme: userPlateforme
  }
}];

// Réponse au webhook après publication
const theme = ((() => { try { return $('Sélecteur Thème').first()?.json; } catch(e) {} try { return $('Parser Webhook').first()?.json; } catch(e) {} return {}; })());
const results = $input.first().json;

return [{
  json: {
    success: true,
    message: "Publication marketing lancée",
    theme: theme.week_theme || "N/A",
    sujet: theme.sujet || "N/A",
    platforms: results.platforms || {},
    date: new Date().toISOString()
  }
}];

// Publication manuelle : envoyer le texte EXACT de l'utilisateur
// Sans reformatage, sans IA, tel quel.
const data = $input.first().json;
const text = data.user_content || '';
const hashtags = data.user_hashtags || '';

// Construire le message final : texte tel quel + hashtags si fournis
let message = text;
if (hashtags.trim()) {
  const formattedHashtags = hashtags.split(/[,\s]+/).filter(Boolean).map(h => h.startsWith('#') ? h : '#' + h).join(' ');
  message += '\n\n' + formattedHashtags;
}

// Config Meta (même que Préparer Facebook)
const META_CONFIG = {
  PAGE_ACCESS_TOKEN: 'A_REMPLACER_PAR_LONG_LIVED_TOKEN',
  PAGE_ID: '1029257496936725'
};

return [{
  json: {
    platform: 'facebook',
    message: message,
    link: 'https://talosprimes.com',
    meta_page_id: META_CONFIG.PAGE_ID,
    meta_access_token: META_CONFIG.PAGE_ACCESS_TOKEN,
    // Infos pour le log
    sujet: data.sujet || 'Publication manuelle',
    content_type: data.content_type || 'manuel',
    week_theme: 'Manuel'
  }
